def build_table_model(migration_files: Iterable[Path]) -> dict[str, _TableRLS]:
    tables: dict[str, _TableRLS] = {}
    for path in migration_files:
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        _scan_sql(text, tables)
    return tables

